namespace sv_75762fffcae24942ab72c74cfd1d3716.Models;

public class Product
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public int Quantity { get; set; }
    public decimal UnitPrice { get; set; }
    public string Category { get; set; } = string.Empty;
}

using sv_75762fffcae24942ab72c74cfd1d3716.Models;

namespace sv_75762fffcae24942ab72c74cfd1d3716.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "Cotton T-Shirt", Quantity = 300, UnitPrice = 14.50m, Category = "Clothing" },
        new Product { Id = 3, Name = "Organic Coffee Beans", Quantity = 80, UnitPrice = 12.99m, Category = "Food" },
        new Product { Id = 4, Name = "USB-C Hub", Quantity = 60, UnitPrice = 49.99m, Category = "Electronics" },
        new Product { Id = 5, Name = "Winter Jacket", Quantity = 45, UnitPrice = 89.95m, Category = "Clothing" },
        new Product { Id = 6, Name = "Notebook & Pen Set", Quantity = 200, UnitPrice = 7.25m, Category = "Other" },
    };

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            var copy = _products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category,
            }).ToList();
            return Task.FromResult(copy);
        }
    }

    public Task UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id)
                ?? throw new ArgumentException($"Product with Id {product.Id} not found.");

            existing.Name = product.Name;
            existing.Quantity = product.Quantity;
            existing.UnitPrice = product.UnitPrice;
            existing.Category = product.Category;
        }
        return Task.CompletedTask;
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using sv_75762fffcae24942ab72c74cfd1d3716.Models
@using sv_75762fffcae24942ab72c74cfd1d3716.Services
@inject InventoryService InventoryService

<PageTitle>Inventory</PageTitle>

<h1>Inventory</h1>

@if (_products is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped table-bordered">
        <thead>
            <tr>
                <th>Name</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Category</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var product in _products)
            {
                @if (_editingProductId == product.Id)
                {
                    <tr>
                        <td>
                            <input type="text" class="form-control" @bind="_editModel!.Name" />
                            @if (!string.IsNullOrEmpty(_nameError))
                            {
                                <div class="text-danger small">@_nameError</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control" @bind="_editModel!.Quantity" />
                            @if (!string.IsNullOrEmpty(_quantityError))
                            {
                                <div class="text-danger small">@_quantityError</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control" step="0.01" @bind="_editModel!.UnitPrice" />
                            @if (!string.IsNullOrEmpty(_priceError))
                            {
                                <div class="text-danger small">@_priceError</div>
                            }
                        </td>
                        <td>
                            <select class="form-select" @bind="_editModel!.Category">
                                <option value="">-- Select --</option>
                                @foreach (var cat in Categories)
                                {
                                    <option value="@cat">@cat</option>
                                }
                            </select>
                            @if (!string.IsNullOrEmpty(_categoryError))
                            {
                                <div class="text-danger small">@_categoryError</div>
                            }
                        </td>
                        <td>
                            <button class="btn btn-success btn-sm me-1" @onclick="SaveAsync">Save</button>
                            <button class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
                        </td>
                    </tr>
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => Edit(product)">Edit</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
}

@code {
    private static readonly string[] Categories = { "Electronics", "Clothing", "Food", "Other" };

    private List<Product>? _products;
    private int? _editingProductId;
    private Product? _editModel;

    private string? _nameError;
    private string? _quantityError;
    private string? _priceError;
    private string? _categoryError;

    protected override async Task OnInitializedAsync()
    {
        _products = await InventoryService.GetAllAsync();
    }

    private void Edit(Product product)
    {
        ClearErrors();
        _editingProductId = product.Id;
        _editModel = new Product
        {
            Id = product.Id,
            Name = product.Name,
            Quantity = product.Quantity,
            UnitPrice = product.UnitPrice,
            Category = product.Category,
        };
    }

    private async Task SaveAsync()
    {
        if (!Validate())
            return;

        await InventoryService.UpdateAsync(_editModel!);
        _products = await InventoryService.GetAllAsync();
        ClearEditState();
    }

    private void Cancel()
    {
        ClearEditState();
    }

    private void ClearEditState()
    {
        _editingProductId = null;
        _editModel = null;
        ClearErrors();
    }

    private void ClearErrors()
    {
        _nameError = null;
        _quantityError = null;
        _priceError = null;
        _categoryError = null;
    }

    private bool Validate()
    {
        ClearErrors();
        var valid = true;

        if (string.IsNullOrWhiteSpace(_editModel!.Name))
        {
            _nameError = "Name is required.";
            valid = false;
        }

        if (_editModel.Quantity < 0 || _editModel.Quantity > 9999)
        {
            _quantityError = "Quantity must be between 0 and 9999.";
            valid = false;
        }

        if (_editModel.UnitPrice <= 0)
        {
            _priceError = "Price must be greater than 0.";
            valid = false;
        }

        if (string.IsNullOrWhiteSpace(_editModel.Category))
        {
            _categoryError = "Category is required.";
            valid = false;
        }

        return valid;
    }
}

