+        _editModel = new Product
+        {
+            Id = product.Id,
+            Name = product.Name,
+            Quantity = product.Quantity,
+            UnitPrice = product.UnitPrice,
+            Category = product.Category,
+        };
+    }
+
+    private async Task SaveAsync()
+    {
+        if (!Validate())
+            return;
+
+        await InventoryService.UpdateAsync(_editModel!);
+        _products = await InventoryService.GetAllAsync();
+        ClearEditState();
+    }
+
+    private void Cancel()
+    {
+        ClearEditState();
+    }
+
+    private void ClearEditState()
+    {
+        _editingProductId = null;
+        _editModel = null;
+        ClearErrors();
+    }
+
+    private void ClearErrors()
+    {
+        _nameError = null;
+        _quantityError = null;
+        _priceError = null;
+        _categoryError = null;
+    }
+
+    private bool Validate()
+    {
+        ClearErrors();
+        var valid = true;
+
+        if (string.IsNullOrWhiteSpace(_editModel!.Name))
+        {
+            _nameError = "Name is required.";
+            valid = false;
+        }
+
+        if (_editModel.Quantity < 0 || _editModel.Quantity > 9999)
+        {
+            _quantityError = "Quantity must be between 0 and 9999.";
+            valid = false;
+        }
+
+        if (_editModel.UnitPrice <= 0)
+        {
+            _priceError = "Price must be greater than 0.";
+            valid = false;
+        }
+
+        if (string.IsNullOrWhiteSpace(_editModel.Category))
+        {
+            _categoryError = "Category is required.";
+            valid = false;
+        }
+
+        return valid;
+    }
+}
